+import React, { useState, useEffect } from 'react'
+import { Container, Grow, Grid, Paper, AppBar, TextField, Button } from '@material-ui/core';
+import Posts from '../Posts/posts';
+import Form from '../Forms/form';
+import Paginate from '../Pagination';
+import ChipInput from '@material-ui/core';
+import useStyle from './styles';
+import { useDispatch } from 'react-redux';
+import { getPosts } from '../../actions/posts';
+import { useHistory, useLocation } from 'react-router-dom';
+
+function useQuery() {
+    return new URLSearchParams(useLocation().search);
+}
+
+const Home = () => {
+    const [currentId, setCurrentId] = useState(0);
+    const dispatch = useDispatch();
+    const query = useQuery();
+    const history = useHistory();
+    const page = query.get('page') || 1;
+    const searchQuery = query.get('searchQuery');
+    const classes = useStyle();
+    const [search, setSearch] = useState('');
+    const [tags, setTags] = useState([]);
+
+    const handleKeyPress = (e) => {
+        if(e.keyCode === 13) {
+            searchPost();
+        };
+    
+    const handleAdd = (tag) => setTags([...tags, tag]);
+
+    const handleDelete = (tagToDelete) => setTags(tags.filter((tag) => tag !== tagToDelete));
+
+    const searchPost = () => {
+        if(search.trim() || tags.length > 0) {
+            dispatch(getPostsBySearch({ search, tags: tags.join(',') }));
+
+            history.push(`/posts/search?searchQuery=${search || 'none'}&tags=${tags.join(',')}`);
+        } else {
+            history.push('/');
+        }
+    };
+    }
+
+    useEffect(() => {
+        dispatch(getPosts());
+    }, [currentId ,dispatch]);
+  return (
+    <Grow in>
+    <Container maxWidth="xl">
+        <Grid  container justifyContent ="space-between" alignItems="stretch" spacing={3} className={classes.gridContainer}>
+            <Grid item xs={12} sm={6} md={9}>
+                <Posts setCurrentId={setCurrentId} />
+            </Grid>
+            <Grid item xs={12} sm={6} md={3}>
+                <AppBar className={classes.appBarSearch} position="static" color="inherit">
+                    <TextField name="search" variant="outlined" label="Search Memories" onKeyPress={handleKeyPress} fullWidth value={search} onChange={(e) => setSearch(e.target.value)} />
+                    <ChipInput style={{ margin: '10px 0' }} value={tags} onAdd={handleAdd} onDelete={handleDelete} label="Search Tags" variant="outlined" />
+                    <Button onClick={searchPost} className={classes.searchButton} variant="contained" color="primary">Search</Button>
+                </AppBar>
+                <Form currentId={currentId} setCurrentId={setCurrentId} />
+                <Paper elevation={6}>
+                    <Paginate />
+                </Paper>
+            </Grid>
+        </Grid>
+    </Container>
+    </Grow>
+  )
+}
+
+export default Home
